"use strict";const emptyArray=Object.freeze([]);class SourceCodeVisitor{#t=new Map;add(t,s){this.#t.has(t)?this.#t.get(t).push(s):this.#t.set(t,[s])}get(t){return this.#t.has(t)?this.#t.get(t):emptyArray}forEachName(t){this.#t.forEach((s,i)=>{t(i)})}callSync(t,...s){this.#t.has(t)&&this.#t.get(t).forEach(t=>t(...s))}}module.exports={SourceCodeVisitor:SourceCodeVisitor};